'use client';

import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { z } from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { List, X } from 'lucide-react';
import { Textarea } from '../ui/textarea';
import React from 'react';
import { useCurrencySymbol } from '@/hooks/use-currency';
import { cn } from '@/lib/utils';

const formSchema = z.object({
  type: z.enum(['income', 'expense']),
  amount: z.coerce.number().positive('Amount must be positive'),
  categoryName: z.string().min(1, 'Category is required'),
  description: z.string().optional(),
});

type AddTransactionProps = {
  children?: React.ReactNode;
  defaultType?: 'income' | 'expense';
};

export function AddTransactionSheet({ 
  children, 
  defaultType = 'expense' 
}: AddTransactionProps) {
  const currencySymbol = useCurrencySymbol();
  const [open, setOpen] = React.useState(false);

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      type: defaultType,
      amount: 0,
      categoryName: '',
      description: '',
    },
  });

  const selectedType = form.watch('type');

  function onSubmit(values: z.infer<typeof formSchema>) {
    console.log('Saving transaction:', values);
    // TODO: Implement actual save logic with Firebase
    setOpen(false);
    form.reset();
  }

  const title = selectedType === 'income' ? 'Add Income' : 'Add Expense';

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {children}
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px] p-0 overflow-hidden rounded-[1.5rem] border-0 shadow-2xl">
        <DialogHeader className="px-8 pt-8 flex flex-row items-center justify-between space-y-0">
          <DialogTitle className="text-2xl font-bold text-[#1e3a8a]">
            {title}
          </DialogTitle>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="px-8 pb-8 space-y-6 pt-4">
            {/* Category Field */}
            <FormField
              control={form.control}
              name="categoryName"
              render={({ field }) => (
                <FormItem className="space-y-2">
                  <FormLabel className="text-sm font-bold text-[#334155]">Category</FormLabel>
                  <FormControl>
                    <div className="flex group">
                      <Input 
                        placeholder="Enter category name" 
                        className="rounded-l-xl rounded-r-none h-12 border-[#cbd5e1] focus:ring-0 focus:border-[#1e3a8a] transition-all"
                        {...field} 
                      />
                      <div className="flex items-center justify-center px-3 border border-l-0 border-[#cbd5e1] rounded-r-xl bg-white text-[#64748b]">
                        <List className="h-5 w-5" />
                      </div>
                    </div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Amount Field */}
            <FormField
              control={form.control}
              name="amount"
              render={({ field }) => (
                <FormItem className="space-y-2">
                  <FormLabel className="text-sm font-bold text-[#334155]">Amount</FormLabel>
                  <FormControl>
                    <div className="flex group">
                      <div className="flex items-center justify-center px-4 border border-r-0 border-[#cbd5e1] rounded-l-xl bg-[#f8fafc] text-[#64748b] font-medium min-w-[3rem]">
                        {currencySymbol || '₹'}
                      </div>
                      <Input 
                        type="number"
                        step="0.01"
                        placeholder="0.00" 
                        className="rounded-r-xl rounded-l-none h-12 border-[#cbd5e1] focus:ring-0 focus:border-[#1e3a8a] transition-all"
                        {...field} 
                      />
                    </div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Description Field */}
            <FormField
              control={form.control}
              name="description"
              render={({ field }) => (
                <FormItem className="space-y-2">
                  <FormLabel className="text-sm font-bold text-[#334155]">Description</FormLabel>
                  <FormControl>
                    <Textarea 
                      placeholder="Enter description..." 
                      className="min-h-[120px] rounded-xl border-[#cbd5e1] focus:ring-0 focus:border-[#1e3a8a] transition-all resize-none p-3"
                      {...field} 
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <Button 
              type="submit" 
              className="w-full h-12 bg-[#1e3a8a] hover:bg-[#1a367c] text-white font-bold text-base rounded-xl transition-all shadow-md mt-2"
            >
              Save Transaction
            </Button>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}
